// -------------------------
// Typed hook
// -------------------------
function useTypedWords(words = [], speed = 80, pause = 1200) {
  const [text, setText] = useState('');
  const [index, setIndex] = useState(0);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    let mounted = true;
    let timeout;

    const current = words[index % words.length];
    if (!deleting) {
      timeout = setTimeout(() => {
        if (!mounted) return;
        setText(current.slice(0, text.length + 1));
        if (text.length + 1 === current.length) {
          setTimeout(() => setDeleting(true), pause);
        }
      }, speed);
    } else {
      timeout = setTimeout(() => {
        if (!mounted) return;
        setText(current.slice(0, text.length - 1));
        if (text.length - 1 === 0) {
          setDeleting(false);
          setIndex((i) => i + 1);
        }
      }, speed / 2);
    }

    return () => {
      mounted = false;
      clearTimeout(timeout);
    };
  }, [text, deleting, index, words, speed, pause]);

  return text;
}

// Reveal on scroll
function Reveal({ children, direction = 'up', delay = 0 }) {
  const ref = useRef(null);
  const [show, setShow] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setShow(true);
            obs.unobserve(el);
          }
        });
      },
      { threshold: 0.12 }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  const variants = {
    hidden: { opacity: 0, y: direction === 'up' ? 30 : 0, x: direction === 'left' ? -30 : 0 },
    visible: { opacity: 1, y: 0, x: 0, transition: { duration: 0.7, delay } },
  };

  return (
    <motion.div ref={ref} initial="hidden" animate={show ? 'visible' : 'hidden'} variants={variants}>
      {children}
    </motion.div>
  );
}

