function TechTicker({ logos = [], speed = 30 }) {
  // speed = seconds for one full loop
  return (
    <Box sx={{ overflow: 'hidden', width: '100%', py: 2 }} aria-hidden={false}>
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          gap: 4,
          whiteSpace: 'nowrap',
          // duplicated content trick: two identical strips for seamless loop
        }}
      >
        <Box
          component="div"
          sx={{
            display: 'inline-flex',
            gap: 6,
            animation: `ticker ${speed}s linear infinite`,
            willChange: 'transform',
            alignItems: 'center',
          }}
        >
          {logos.concat(logos).map((l, i) => (
            <Box key={i} sx={{ display: 'flex', alignItems: 'center' }}>
              <Box component="img" src={l.src} alt={l.alt} sx={{ height: 36, width: 'auto', filter: (t) => (t.palette.mode === 'dark' ? 'brightness(1.1)' : 'none') }} />
            </Box>
          ))}
        </Box>
      </Box>

      <style>{`
        @keyframes ticker {
          0% { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }
      `}</style>
    </Box>
  );
}

