function ContactCard({ onSend }) {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [message, setMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const valid = name.trim() && email.trim() && message.trim();

  const handleSubmit = (ev) => {
    ev.preventDefault();
    if (!valid) {
      setError('Por favor completa todos los campos.');
      return;
    }

    setError(null);
    setLoading(true);

    const subject = encodeURIComponent(`Contacto desde portafolio: ${name}`);
    const body = encodeURIComponent(`Nombre: ${name}\nEmail: ${email}\n\n${message}`);
    window.location.href = `mailto:${CONTACT.email}?subject=${subject}&body=${body}`;

    setTimeout(() => {
      setLoading(false);
      setName('');
      setEmail('');
      setMessage('');
      onSend && onSend();
    }, 700);
  };

  return (
    <Card component="form" onSubmit={handleSubmit} sx={{ p: 2 }} aria-label="contact-form">
      <CardContent>
        <Typography variant="h6">Envíame un mensaje</Typography>
        <Typography color="text.secondary" sx={{ mb: 2, fontSize: 13 }}>
          Prefiero mensajes claros y con contexto — así puedo responder mejor.
        </Typography>

        <TextField label="Nombre" fullWidth size="small" value={name} onChange={(e) => setName(e.target.value)} sx={{ mb: 1 }} />
        <TextField label="Email" fullWidth size="small" value={email} onChange={(e) => setEmail(e.target.value)} sx={{ mb: 1 }} />
        <TextField
          label="Mensaje"
          fullWidth
          size="small"
          multiline
          rows={4}
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          sx={{ mb: 2 }}
        />

        {error && (
          <Alert severity="warning" sx={{ mb: 1 }}>
            {error}
          </Alert>
        )}

        <Box sx={{ display: 'flex', gap: 1, justifyContent: 'flex-end' }}>
          <Button variant="outlined" size="small" onClick={() => { setName(''); setEmail(''); setMessage(''); }}>
            Limpiar
          </Button>
          <Button variant="contained" type="submit" disabled={!valid || loading}>
            {loading ? 'Abriendo...' : 'Enviar'}
          </Button>
        </Box>
      </CardContent>
    </Card>
  );
}

